SELECT c.comment_id, c.user_id, c.work_id, c.parent_comment_id, c.in_comment_id, c.comment_floor, c.comment_text, c.approval_status, c.is_delete, c.time, u.nickname, w.work_title FROM tb_comments c LEFT JOIN tb_works w ON c.work_id = w.work_id LEFT JOIN tb_user u ON c.user_id = u.user_id WHERE c.is_delete = 0
AND c.work_id = #{workId}
AND c.user_id = #{userId}
AND c.comment_floor = #{commentFloor}
AND c.approval_status = #{approvalStatus}
AND c.comment_text LIKE CONCAT('%', #{keyword}, '%')
ORDER BY
c.time ASC
c.time DESC
